import XCTest
@testable import MeuApp  // acesso a internals do módulo

final class TarefaViewModelTests: XCTestCase {

    // tearDown roda depois de cada teste — garante estado limpo:
    override func tearDown() {
        super.tearDown()
    }

    func test_adicionarTarefa_incrementaLista() {
        // Arrange — estado inicial:
        let vm = TarefasViewModel(repositorio: TarefaFake())
        XCTAssertEqual(vm.tarefas.count, 0)

        // Act — ação que está sendo testada:
        vm.adicionar(titulo: "Nova Tarefa")

        // Assert — resultado esperado:
        XCTAssertEqual(vm.tarefas.count, 1)
        XCTAssertEqual(vm.tarefas[0].titulo, "Nova Tarefa")
    }

    func test_marcarConcluida_mudaStatus() {
        // Arrange:
        let vm = TarefasViewModel(repositorio: TarefaFake())
        vm.adicionar(titulo: "Tarefa")
        let tarefa = vm.tarefas[0]

        // Act:
        vm.marcarConcluida(tarefa)

        // Assert:
        XCTAssertTrue(vm.tarefas[0].concluida)
    }
}

func test_carregarTarefas_populaLista() async throws {
    // Arrange:
    let fake = TarefaFake()
    fake.retornar = [
        Tarefa(titulo: "A", concluida: false),
        Tarefa(titulo: "B", concluida: true)
    ]
    let vm = TarefasViewModel(repositorio: fake)

    // Act:
    try await vm.carregarTarefas()

