// Protocolo de dependência:
protocol TarefaRepositorioProtocol {
    func buscarTodas() async throws -> [Tarefa]
    func salvar(_ tarefa: Tarefa) async throws
    func deletar(_ tarefa: Tarefa) async throws
}

// Fake — implementação em memória:
final class TarefaFake: TarefaRepositorioProtocol {
    var tarefas: [Tarefa] = []
    var simularErro = false
    var erroRetornado: Error = NSError(domain: "test", code: -1)

    func buscarTodas() async throws -> [Tarefa] {
        if simularErro { throw erroRetornado }
        return tarefas
    }

    func salvar(_ tarefa: Tarefa) async throws {
        if simularErro { throw erroRetornado }
        if let index = tarefas.firstIndex(where: { $0.id == tarefa.id }) {
            tarefas[index] = tarefa  // atualiza existente
        } else {
            tarefas.append(tarefa)  // adiciona novo
        }
    }

    func deletar(_ tarefa: Tarefa) async throws {
        tarefas.removeAll { $0.id == tarefa.id }
    }
}

// Spy — registra chamadas:
final class AnalyticsSpy: AnalyticsProtocol {
    var eventoRegistrados: [(nome: String, parametros: [String: Any])] = []

    func registrar(evento: String, parametros: [String: Any]) {
        eventoRegistrados.append((nome: evento, parametros: parametros))
    }
}

// Teste usando o Spy:
func test_concluirTarefa_registraEvento() async throws {
    let spy = AnalyticsSpy()
    let vm = TarefasViewModel(repositorio: TarefaFake(), analytics: spy)
    vm.adicionar(titulo: "Tarefa")

    vm.marcarConcluida(vm.tarefas[0])

    XCTAssertEqual(spy.eventoRegistrados.count, 1)
    XCTAssertEqual(spy.eventoRegistrados[0].nome, "tarefa_concluida")
}

import XCTest

final class LoginUITests: XCTestCase {
    var app: XCUIApplication!

    override func setUp() {
        super.setUp()
        continueAfterFailure = false  // para imediatamente no primeiro erro
        app = XCUIApplication()
        app.launchArguments = ["--uitesting"]  // flag para modo de teste
        app.launch()
    }

    func test_loginComSucesso_navegaParaHome() {
        // Encontra campos por accessibilityIdentifier:
        let campoEmail = app.textFields["campo-email"]
        let campoSenha = app.secureTextFields["campo-senha"]
        let botaoEntrar = app.buttons["botao-entrar"]

        // Interage como o usuário:
        campoEmail.tap()
        campoEmail.typeText("usuario@email.com")

        campoSenha.tap()
        campoSenha.typeText("senha123")

        botaoEntrar.tap()

        // Verifica que navegou para home:
        let titulo = app.staticTexts["tela-home-titulo"]
        XCTAssertTrue(titulo.waitForExistence(timeout: 5))
    }
}

